@RestController
class SamlController {
    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping("/saml/login")
    public ResponseEntity<Void> login() {
        String redirectUrl = samlService.buildRedirectAuthnRequest();
        return ResponseEntity.status(302).header(HttpHeaders.LOCATION, redirectUrl).build();
    }

    @PostMapping(value = "/saml/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<SamlUser> acs(@RequestParam("SAMLResponse") String samlResponse) {
        SamlUser user = samlService.parseResponse(samlResponse);
        return ResponseEntity.ok(user);
    }

    @GetMapping(value = "/saml/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public ResponseEntity<String> metadata() {
        return ResponseEntity.ok(samlService.generateMetadata());
    }

    @GetMapping("/saml/logout")
    public ResponseEntity<String> logout() {
        return ResponseEntity.ok("SLO endpoint placeholder");
    }
}

